.darma-loader-loaders-css-21 {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 6px;
      min-width: 51px;
      min-height: 22px;
    }
    .darma-loader-loaders-css-21 i {
      display: block;
      width: 11px;
      height: 11px;
      border-radius: 50%;
      background: var(--loader-color, #8b5cf6);
      animation: darma-loader-loaders-css-21-dotPulse 0.7799999999999999s ease-in-out infinite;
    }
    .darma-loader-loaders-css-21 i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-loaders-css-21 i:nth-child(2) { animation-delay: 0.12s; }
.darma-loader-loaders-css-21 i:nth-child(3) { animation-delay: 0.24s; }
    @keyframes darma-loader-loaders-css-21-dotPulse { 0%, 80%, 100% { opacity: .25; transform: scale(.7); } 40% { opacity: 1; transform: scale(1); } }

